object IoTApiClient {
    private const val CLOUD_BASE_URL = "https://api.example.com"
    
    private val httpClient = IoTHttpClient()
    
    suspend fun getCloudDevices(authToken: String): Response {
        val headers = mapOf(
            "Authorization" to "Bearer $authToken",
            "Content-Type" to "application/json"
        )
        return httpClient.get("$CLOUD_BASE_URL/devices", headers)
    }
    
    suspend fun getLocalDeviceStatus(ipAddress: String): Response {
        return httpClient.get("http://$ipAddress/status")
    }
    
    suspend fun controlLocalDevice(ipAddress: String, command: String): Response {
        return httpClient.post(
            url = "http://$ipAddress/control",
            body = """{"command": "$command"}"""
        )
    }
    
    suspend fun updateCloudDevice(deviceId: String, data: String, authToken: String): Response {
        val headers = mapOf(
            "Authorization" to "Bearer $authToken",
            "Content-Type" to "application/json"
        )
        return httpClient.put("$CLOUD_BASE_URL/devices/$deviceId", data, headers = headers)
    }
    
    suspend fun deleteCloudDevice(deviceId: String, authToken: String): Response {
        val headers = mapOf(
            "Authorization" to "Bearer $authToken"
        )
        return httpClient.delete("$CLOUD_BASE_URL/devices/$deviceId", headers)
    }
    
    suspend fun getLocalDeviceConfig(ipAddress: String): Response {
        return httpClient.get("http://$ipAddress/config")
    }
    
    suspend fun updateLocalDeviceConfig(ipAddress: String, config: String): Response {
        return httpClient.post(
            url = "http://$ipAddress/config",
            body = config
        )
    }
}